const now = new Date();

return items.filter(item => {
  const due = new Date(item.json.due_at);

  return due < now;
});

const isEmpty =
  items.length === 0 ||
  !items[0].json ||
  Object.keys(items[0].json).length === 0;

return [{
  json: {
    already_sent: !isEmpty
  }
}];

const validStages = [
  "Completed",
  "Payment Pending",
  "Closed Won"
];

// Check if data exists properly
const hasData =
  items.length > 0 &&
  items[0].json &&
  Object.keys(items[0].json).length > 0;

// Get stage safely
const stage = hasData ? items[0].json.pipeline_stage : null;

// Validate stage
const isValid = validStages.includes(stage);

return [{
  json: {
    ...items[0]?.json,
    valid_stage: isValid,
    debug_stage: stage // optional (for debugging)
  }
}];

// Check if current CST time is within operating hours (6am–10pm)
const now = new Date(new Date().toLocaleString('en-US', { timeZone: 'America/Chicago' }));
const h = now.getHours();
return [{
  json: {
    current_hour_cst: h,
    within_hours: h >= 6 && h <= 22,
    run_timestamp: new Date().toISOString()
  }
}];

// Apply all three conditions that Supabase filters can't handle natively:
// 1. due_at < NOW()  (72 hours have passed since quote was sent)
// 2. resolved = false  (double-check in JS for safety)
// 3. 24hr cooldown: last_notified_at IS NULL OR last_notified_at < NOW() - 24hrs

const now = new Date();
const cooldownThreshold = new Date(now.getTime() - 24 * 60 * 60 * 1000);

const filtered = items.filter(item => {
  const d = item.json;

  const isNotResolved = d.resolved === false || d.resolved === 'false';
  const isOverdue = d.due_at && new Date(d.due_at) < now;
  const cooldownPassed =
    !d.last_notified_at ||
    new Date(d.last_notified_at) < cooldownThreshold;

  return isNotResolved && isOverdue && cooldownPassed;
});

// Pass through filtered items
return filtered.length > 0 ? filtered : [];

// Node 22B Logic:
// Increment notification_count and check if >= 3 (closed-lost candidate threshold)
const esc = $('Code — Calc Days Since Quote Sent1').item.json;
const newCount = (esc.notification_count || 0) + 1;
const isClosedLostCandidate = newCount >= 3;

return [{
  json: {
    ...esc,
    new_notification_count: newCount,
    is_closed_lost_candidate: isClosedLostCandidate
  }
}];

// Calculate days since quote was originally sent.
// Quote was sent 72hrs before due_at, so: sent_at = due_at - 72hrs
const esc = $input.item.json;

const dueDateMs = new Date(esc.due_at).getTime();
const quoteSentMs = dueDateMs - (72 * 60 * 60 * 1000);
const daysSince = Math.max(0, Math.floor((Date.now() - quoteSentMs) / (1000 * 60 * 60 * 24)));

return [{
  json: {
    ...esc,
    days_since: daysSince,
    quote_sent_at: new Date(quoteSentMs).toISOString()
  }
}];

return items.filter(item => {
  const data = item.json;

  const validType =
    data.type === 'quote_not_sent' ||
    data.type === 'quote_approval_pending';

  const twelveHoursAgo = new Date(Date.now() - 12 * 60 * 60 * 1000);

  const notRecentlyNotified =
    !data.last_notified_at ||
    new Date(data.last_notified_at) < twelveHoursAgo;

  return validType && notRecentlyNotified;
});

const esc = $input.first().json;
if (!esc.lead_id) return [];
const hoursOverdue = Math.floor((Date.now() - new Date(esc.due_at).getTime()) / 3600000);
return [{ json: { ...esc, hours_overdue: hoursOverdue } }];

return items.filter(item => {
  const data = item.json;

  // ✅ Allowed stages
  const validStages = [
    'Completed',
    'Payment Pending',
    'Closed Won'
  ];

  const isValidStage = validStages.includes(data.pipeline_stage);

  // ✅ Newsletter timing logic (SAFE)
  let lastSent = null;

  if (data.last_newsletter_sent_at) {
    const parsedDate = new Date(data.last_newsletter_sent_at);
    if (!isNaN(parsedDate)) {
      lastSent = parsedDate;
    }
  }

  const now = new Date();
  const ninetyDaysAgo = new Date(now.getTime() - 90 * 24 * 60 * 60 * 1000);

  const isDueNewsletter = !lastSent || lastSent < ninetyDaysAgo;

  return isValidStage && isDueNewsletter;
});
